/* ------------------------------------------------------------------
 * LinkedList implementation – secure, defensive style
 * ------------------------------------------------------------------ */

/* Forward declarations */
typedef struct Node {
    int value;
    struct Node *next;
} Node;

typedef struct LinkedList {
    Node *head;
    size_t size;
} LinkedList;

/* ------------------------------------------------------------------
 * Helper: create a new node
 * ------------------------------------------------------------------ */
static Node *createNode(int value)
{
    Node *node = malloc(sizeof(Node));
    if (!node) {
        /* Allocation failed – caller can decide how to handle */
        return NULL;
    }
    node->value = value;
    node->next  = NULL;
    return node;
}

/* ------------------------------------------------------------------
 * Public API
 * ------------------------------------------------------------------ */

/* Create an empty list */
LinkedList *createList(void)
{
    LinkedList *list = malloc(sizeof(LinkedList));
    if (!list) {
        return NULL;          /* caller must check */
    }
    list->head = NULL;
    list->size = 0;
    return list;
}

/* Check if the list is empty – safe even if list is NULL */
bool isEmpty(const LinkedList *list)
{
    /* Treat a NULL list as empty – this is a design choice that
     * prevents accidental dereference in callers that may not
     * guarantee a non‑NULL list. */
    return (list == NULL) || (list->head == NULL);
}

/* Insert a value at the beginning of the list.
 * Returns true on success, false on failure (e.g., NULL list or
 * memory allocation failure). */
bool insertAtBeginning(LinkedList *list, int value)
{
    /* Defensive check – avoid NULL dereference */
    if (!list) {
        /* Log the error if a logging facility is available */
        /* e.g., log_error("insertAtBeginning called with NULL list"); */
        return false;
    }

    Node *newNode = createNode(value);
    if (!newNode) {
        /* Allocation failed – caller can retry or handle */
        return false;
    }

    /* Insert at the front */
    newNode->next = list->head;
    list->head    = newNode;
    list->size++;

    return true;
}

/* ------------------------------------------------------------------
 * Optional: helper to free the list (for completeness)
 * ------------------------------------------------------------------ */
void freeList(LinkedList *list)
{
    if (!list) return;

    Node *current = list->head;
    while (current) {
        Node *next = current->next;
        free(current);
        current = next;
    }
    free(list);
}
