 * ------------------------------------------------------------------ */
typedef struct node {
    void   *data;          /* Pointer to user data (deep‑copied) */
    size_t  size;          /* Size of the data buffer */
    struct node *next;     /* Next node in the list */
} node_t;

/* ------------------------------------------------------------------
 *  Memory‑pool structure
 * ------------------------------------------------------------------ */
typedef struct {
    unsigned char *base;   /* Base of the pool */
    size_t        capacity;/* Total capacity in bytes */
    size_t        used;    /* Bytes currently used */
} mempool_t;

/* ------------------------------------------------------------------
 *  Global pool instance
 * ------------------------------------------------------------------ */
static mempool_t g_pool = { NULL, 0, 0 };

/* ------------------------------------------------------------------
 *  Initialise the memory pool
 * ------------------------------------------------------------------ */
static void pool_init(void)
{
    if (g_pool.base != NULL) {
        /* Pool already initialised – avoid double‑initialisation */
        return;
    }

    g_pool.capacity = BLOCK_SIZE * POOL_CAPACITY;
    g_pool.base = calloc(1, g_pool.capacity);
    if (!g_pool.base) {
        fprintf(stderr, "Fatal: Unable to initialise memory pool (%zu bytes).\n",
                g_pool.capacity);
        exit(EXIT_FAILURE);
    }
    g_pool.used = 0;
}

/* ------------------------------------------------------------------
 *  Allocate a node from the pool
 * ------------------------------------------------------------------ */
static node_t *pool_alloc_node(const void *data, size_t size)
{
    /* Ensure the pool is ready */
    pool_init();

    /* Bounds check – we need at least BLOCK_SIZE bytes for the node */
    if (g_pool.used + BLOCK_SIZE > g_pool.capacity) {
        fprintf(stderr,
                "Error: Memory pool exhausted – cannot allocate new node.\n");
        exit(EXIT_FAILURE);
    }

    /* Allocate the node from the pool */
    node_t *node = (node_t *)(g_pool.base + g_pool.used);
    g_pool.used += BLOCK_SIZE;

    /* Zero‑initialise the node to avoid uninitialised data */
    memset(node, 0, sizeof(node_t));

    /* Deep‑copy the user data */
    if (size > 0) {
        node->data = calloc(1, size);
        if (!node->data) {
            fprintf(stderr,
                    "Error: Unable to allocate data buffer (%zu bytes).\n",
                    size);
            exit(EXIT_FAILURE);
        }
        memcpy(node->data, data, size);
        node->size = size;
    } else {
        node->data = NULL;
        node->size = 0;
    }

    node->next = NULL;
    return node;
}

/* ------------------------------------------------------------------
 *  Deallocate a node (returns it to the pool)
 * ------------------------------------------------------------------ */
static void pool_free_node(node_t *node)
{
    if (!node) return;

    /* Free the deep‑copied data buffer */
    free(node->data);
    node->data = NULL;
    node->size = 0;

    /* In a real pool implementation we would maintain a free‑list.
       For simplicity we just zero the node – the pool will be
       reused in the next allocation. */
    memset(node, 0, sizeof(node_t));
}

/* ------------------------------------------------------------------
 *  Example usage
 * ------------------------------------------------------------------ */
int main(void)
{
    /* Example data to store in a node */
    const char sample[] = "Hello, secure world!";

    /* Allocate a node safely */
    node_t *my_node = pool_alloc_node(sample, sizeof(sample));

    /* Use the node… */
    printf("Node data: %s\n", (char *)my_node->data);

    /* Clean up */
    pool_free_node(my_node);

    /* Release the entire pool at program exit */
    free(g_pool.base);
    g_pool.base = NULL;
    g_pool.capacity = 0;
    g_pool.used = 0;

    return 0;
}
```

