#ifndef CPU_USAGE_H
#define CPU_USAGE_H

#include <sys/resource.h>
#include <sys/time.h>
#include <stdint.h>

/* Convert a timeval to a double (seconds + microseconds/1e6) */
static inline double timeval_to_double(const struct timeval *tv)
{
    return (double)tv->tv_sec + (double)tv->tv_usec / 1e6;
}

/* Safe division – returns 0.0 if denominator <= 0.0 */
static inline double safe_divide(double numerator, double denominator)
{
    return (denominator > 0.0) ? (numerator / denominator) : 0.0;
}

/* Compute CPU usage percentage for the current process.
 * Returns a value in [0.0, 100.0] (or 0.0 if elapsed time is zero). */
static inline double get_cpu_usage_percent(const struct timeval *start,
                                           const struct timeval *end)
{
    struct rusage usage;
    if (getrusage(RUSAGE_SELF, &usage) != 0) {
        /* In a real system you might log errno here; for safety return 0.0 */
        return 0.0;
    }

    /* CPU time used by this process (user + system) */
    double cpu_time = timeval_to_double(&usage.ru_utime) +
                      timeval_to_double(&usage.ru_stime);

    /* Wall‑clock elapsed time between start and end */
    double elapsed = timeval_to_double(end) - timeval_to_double(start);

    /* Guard against division by zero or negative elapsed time */
    if (elapsed <= 0.0) {
        return 0.0;
    }

    /* CPU usage percentage */
    double usage_percent = safe_divide(cpu_time, elapsed) * 100.0;

    /* Clamp to [0.0, 100.0] – protects against any floating‑point quirks */
    if (usage_percent < 0.0)  usage_percent = 0.0;
    if (usage_percent > 100.0) usage_percent = 100.0;

    return usage_percent;
}

#endif /* CPU_USAGE_H */
