#include <stddef.h>   /* for size_t */

#define MAX_QUEUE_SIZE 1024   /* adjust as needed */

typedef struct {
    size_t front;   /* index of the first element, or MAX_QUEUE_SIZE if empty */
    size_t rear;    /* index of the last element, or MAX_QUEUE_SIZE if empty */
    int data[MAX_QUEUE_SIZE];
} queue_t;

/* Initialise a queue – caller must provide a valid pointer */
void queue_init(queue_t *queue);

/* Queue status helpers */
bool is_queue_full(const queue_t *queue);
bool is_queue_empty(const queue_t *queue);

#endif /* QUEUE_H */

