#include "queue.h"
#include <string.h>   /* for memset */

/* --------------------------------------------------------------------------- */
/* Initialise the queue.  The caller must supply a non‑NULL pointer.           */
/* --------------------------------------------------------------------------- */
void queue_init(queue_t *queue)
{
    /* Defensive programming: guard against accidental NULL pointer */
    if (queue == NULL) {
        /* In a production system you might log this error or abort. */
        return;
    }

    /* Use a sentinel value that is outside the valid index range. */
    queue->front = MAX_QUEUE_SIZE;   /* empty queue */
    queue->rear  = MAX_QUEUE_SIZE;   /* empty queue */

    /* Optional: clear the data buffer to avoid stale data exposure. */
    memset(queue->data, 0, sizeof(queue->data));
}

/* --------------------------------------------------------------------------- */
/* Check if the queue is full.  The function is const‑qualified to emphasize   */
/* that it does not modify the queue state.  It also guards against a NULL    */
/* pointer.  The logic uses modulo arithmetic to wrap around.                 */
/* --------------------------------------------------------------------------- */
bool is_queue_full(const queue_t *queue)
{
    if (queue == NULL) {
        /* A NULL queue cannot be full – treat as false. */
        return false;
    }

    /* If the queue is empty, it cannot be full. */
    if (queue->front == MAX_QUEUE_SIZE) {
        return false;
    }

    /* Compute the next rear position and compare with front. */
    size_t next_rear = (queue->rear + 1) % MAX_QUEUE_SIZE;
    return next_rear == queue->front;
}

/* --------------------------------------------------------------------------- */
/* Check if the queue is empty.  The function is const‑qualified and guards   */
/* against a NULL pointer.                                                     */
/* --------------------------------------------------------------------------- */
bool is_queue_empty(const queue_t *queue)
{
    if (queue == NULL) {
        /* A NULL queue is considered empty. */
        return true;
    }

    /* The sentinel value indicates emptiness. */
    return queue->front == MAX_QUEUE_SIZE;
}
