The original code uses `scanf("%d", &lightIntensity);`. While `scanf` with `%d` does not read a string buffer, it can still lead to undefined behavior if the input stream contains malformed data or if the program is compiled with a non‑standard `int` size. A safer, more robust approach is to read the entire line into a fixed‑size buffer with `fgets`, then convert it to an integer using `strtol`, and finally validate the value.

```c
#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>

/* Maximum length of the input line (including the terminating '\n') */
#define MAX_INPUT_LEN  16

/* Safely read an integer from stdin and validate it */
static int read_int_in_range(const char *prompt,
                             int min_val,
                             int max_val,
                             int *out_value)
{
    char buffer[MAX_INPUT_LEN];
    char *endptr;
    long val;

    /* Prompt the user */
    printf("%s", prompt);

    /* Read a line of input */
    if (fgets(buffer, sizeof(buffer), stdin) == NULL) {
        /* EOF or read error */
        return -1;
    }

    /* Remove trailing newline if present */
    buffer[strcspn(buffer, "\n")] = '\0';

    /* Reset errno before conversion */
    errno = 0;
    val = strtol(buffer, &endptr, 10);

    /* Check for conversion errors */
    if (errno != 0 || endptr == buffer || *endptr != '\0') {
        /* Non‑numeric input or overflow/underflow */
        return -1;
    }

    /* Ensure the value fits in an int */
    if (val < INT_MIN || val > INT_MAX) {
        return -1;
    }

    /* Range check */
    if (val < min_val || val > max_val) {
        return -1;
    }

    *out_value = (int)val;
    return 0;
}

/* Example usage in the switch case */
case 3: {
    int new_intensity;
    if (read_int_in_range("Enter new light intensity (0 to 100): ",
                          0, 100, &new_intensity) != 0) {
        printf("Invalid light intensity!\n");
    } else {
        changeLightIntensity(new_intensity);
    }
    break;
}
```

