> **NOTE**: The patch assumes the rest of the queue implementation (enqueue, dequeue, etc.) follows the same style. If you have additional functions that access `queue->front` or `queue->rear`, apply the same NULL‑check pattern there.

```c
/* queue.h – public interface ------------------------------------------------ */
#ifndef QUEUE_H
#define QUEUE_H

#include <stdbool.h>
#include <stddef.h>   /* for size_t */

#define MAX_QUEUE_SIZE 1024   /* adjust as needed */

typedef struct {
    size_t front;   /* index of the first element, or MAX_QUEUE_SIZE if empty */
    size_t rear;    /* index of the last element, or MAX_QUEUE_SIZE if empty */
    int data[MAX_QUEUE_SIZE];
} queue_t;

/* Initialise a queue – caller must provide a valid pointer */
void queue_init(queue_t *queue);

/* Queue status helpers */
bool is_queue_full(const queue_t *queue);
bool is_queue_empty(const queue_t *queue);

#endif /* QUEUE_H */

/* queue.c – implementation --------------------------------------------------- */
#include "queue.h"
#include <string.h>   /* for memset */

/* --------------------------------------------------------------------------- */
/* Initialise the queue.  The caller must supply a non‑NULL pointer.  The
 * function performs a defensive NULL check and returns immediately if the
 * pointer is NULL.  This protects against accidental dereference in the
 * caller. */
void queue_init(queue_t *queue)
{
    if (queue == NULL) {
        /* In a production system you might log this error or abort.  For
         * this example we simply return – the caller should check the
         * return value if it wants to be notified. */
        return;
    }

    /* Use MAX_QUEUE_SIZE as a sentinel value that indicates “empty”.
     * This eliminates the need for negative indices and keeps all
     * arithmetic unsigned. */
    queue->front = MAX_QUEUE_SIZE;
    queue->rear  = MAX_QUEUE_SIZE;

    /* Optional: clear the data buffer to avoid leaking stale data. */
    memset(queue->data, 0, sizeof(queue->data));
}

/* --------------------------------------------------------------------------- */
/* Return true if the queue is full.  The function accepts a const pointer
 * and performs a NULL check.  If the pointer is NULL, the function
 * conservatively reports “full” to avoid a potential buffer overflow
 * in the caller. */
bool is_queue_full(const queue_t *queue)
{
    if (queue == NULL) {
        /* Treat a NULL queue as full – this is a defensive choice that
         * prevents accidental writes to an uninitialised buffer. */
        return true;
    }

    /* The queue is full when the next rear position would collide with
     * the front.  Because we use MAX_QUEUE_SIZE as the empty sentinel,
     * we must also handle the case where the queue is empty. */
    if (queue->front == MAX_QUEUE_SIZE) {
        return false;   /* empty queue cannot be full */
    }

    return ((queue->rear + 1) % MAX_QUEUE_SIZE) == queue->front;
}

/* --------------------------------------------------------------------------- */
/* Return true if the queue is empty.  The function accepts a const pointer
 * and performs a NULL check.  If the pointer is NULL, the function
 * conservatively reports “empty”. */
bool is_queue_empty(const queue_t *queue)
{
    if (queue == NULL) {
        /* A NULL queue is considered empty – this avoids dereferencing
         * a NULL pointer in the caller. */
        return true;
    }

    return queue->front == MAX_QUEUE_SIZE;
}

/* --------------------------------------------------------------------------- */
/* Example enqueue/dequeue functions (minimal, secure) ----------------------- */
bool enqueue(queue_t *queue, int value)
{
    if (queue == NULL) return false;

    if (is_queue_full(queue)) return false;

    if (is_queue_empty(queue)) {
        /* First element – initialise front and rear to 0 */
        queue->front = 0;
        queue->rear  = 0;
    } else {
        queue->rear = (queue->rear + 1) % MAX_QUEUE_SIZE;
    }

    queue->data[queue->rear] = value;
    return true;
}

bool dequeue(queue_t *queue, int *value)
{
    if (queue == NULL || value == NULL) return false;

    if (is_queue_empty(queue)) return false;

    *value = queue->data[queue->front];

    if (queue->front == queue->rear) {
        /* Queue becomes empty – reset sentinel */
        queue->front = MAX_QUEUE_SIZE;
        queue->rear  = MAX_QUEUE_SIZE;
    } else {
        queue->front = (queue->front + 1) % MAX_QUEUE_SIZE;
    }

    return true;
}
```

