    double dy = o2->pos.y - o1->pos.y;
    double dz = o2->pos.z - o1->pos.z;

    /* `hypot` is defined as sqrt(dx*dx + dy*dy + dz*dz) but
     * performs the calculation in a numerically stable way,
     * preventing overflow/underflow in the intermediate sums. */
    return hypot(hypot(dx, dy), dz);
}

/* ------------------------------------------------------------------
 *  Main: Compute gravitational force vector
 *  • Returns a zero vector if the objects occupy the same position
 *    (avoids division by zero).
 *  • All arithmetic is performed with `double`; no unchecked
 *    casts or pointer arithmetic.
