{
    /* Validate input pointers */
    if (!obj1 || !obj2) {
        point zero = {0.0, 0.0, 0.0};
        return zero;
    }

    /* Compute distance once */
    double dist = safe_distance(obj1, obj2);

    /* Guard against zero distance */
    if (dist == 0.0) {
        point zero = {0.0, 0.0, 0.0};
        return zero;
    }

    /* Force magnitude: G * m1 * m2 / dist² */
    double force_mag = GRAV_CONST * obj1->mass * obj2->mass / (dist * dist);

    /* Direction vector (normalized) */
    double dx = obj2->pos.x - obj1->pos.x;
    double dy = obj2->pos.y - obj1->pos.y;
    double dz = obj2->pos.z - obj1->pos.z;

    point force = {
        force_mag * dx / dist,
        force_mag * dy / dist,
        force_mag * dz / dist
