#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <netdb.h>
#include <sys/types.h>
#include <sys/socket.h>

/*  Connect to the host specified on the command line.
 *  Returns a connected socket descriptor on success, or -1 on error.
 */
int connect_to_server(const char *host, const char *port)
{
    struct addrinfo hints, *res, *p;
    int sockfd = -1;
    int rv;

    /*  Prepare hints: IPv4 or IPv6, stream socket (TCP)  */
    memset(&hints, 0, sizeof hints);
    hints.ai_family   = AF_UNSPEC;      /* Allow IPv4 or IPv6 */
    hints.ai_socktype = SOCK_STREAM;    /* TCP */

    /*  Resolve the host name */
    rv = getaddrinfo(host, port, &hints, &res);
    if (rv != 0) {
