/*  Secure connection helper – C99  */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <unistd.h>
#include <netdb.h>
#include <arpa/inet.h>
#include <sys/types.h>
#include <sys/socket.h>

/*  Custom error‑handling routine – closes socket if open  */
static void die(const char *msg, int sock)
{
    if (sock >= 0) close(sock);
    perror(msg);
    exit(EXIT_FAILURE);
}

/*  Resolve host/port and connect – returns a valid socket fd  */
int connect_to_host(const char *host, const char *port_str)
{
    /*  Validate input pointers  */
    if (!host || !port_str) {
        fprintf(stderr, "Error: host or port string is NULL\n");
        exit(EXIT_FAILURE);
    }

    /*  Convert port string to integer safely  */
    char *endptr;
    long port = strtol(port_str, &endptr, 10);
    if (*endptr != '\0' || port <= 0 || port > 65535) {
        fprintf(stderr, "Error: invalid port '%s'\n", port_str);
        exit(EXIT_FAILURE);
    }

    /*  Prepare hints for getaddrinfo  */
    struct addrinfo hints, *res, *p;
    memset(&hints, 0, sizeof hints);
    hints.ai_family   = AF_UNSPEC;      /* IPv4 or IPv6 */
    hints.ai_socktype = SOCK_STREAM;    /* TCP */

    int gai_err = getaddrinfo(host, port_str, &hints, &res);
    if (gai_err != 0) {
        fprintf(stderr, "getaddrinfo: %s\n", gai_strerror(gai_err));
        exit(EXIT_FAILURE);
    }

    int sock = -1;
    for (p = res; p != NULL; p = p->ai_next) {
        /*  Create socket  */
        sock = socket(p->ai_family, p->ai_socktype, p->ai_protocol);
        if (sock == -1) continue;   /* try next address */

        /*  Attempt connection  */
        if (connect(sock, p->ai_addr, p->ai_addrlen) == -1) {
            close(sock);
            sock = -1;
            continue;               /* try next address */
        }
        break;                      /* success */
    }

    freeaddrinfo(res);

    if (sock == -1) {
        die("connect", -1);          /* socket already closed */
    }

    return sock;                     /* caller must close when done */
}
