/*  insertAtEnd.c
 *
 *  Secure implementation of inserting a node at the end of a singly linked list.
 *  Returns 0 on success, -1 on failure (e.g., NULL list or memory allocation error).
 */

#include <stdlib.h>
#include <stdio.h>

/* Forward declarations – assume these are defined elsewhere in the project. */
typedef struct Node {
    int value;
    struct Node *next;
} Node;

typedef struct LinkedList {
    Node *head;
} LinkedList;

/* Create a new node with the given value.  Returns NULL on allocation failure. */
static Node* createNode(int value) {
    Node *node = (Node*)malloc(sizeof(Node));
    if (!node) {
        /* Allocation failed – caller will handle the error. */
        return NULL;
    }
    node->value = value;
    node->next  = NULL;
    return node;
}

/* Check whether the list is empty.  Returns 1 if empty, 0 otherwise. */
static int isEmpty(const LinkedList *list) {
    return (list->head == NULL);
}

/* Insert a new node at the end of the list.  Returns 0 on success, -1 on failure. */
int insertAtEnd(LinkedList *list, int value) {
    /* 1. Validate the list pointer. */
    if (!list) {
        /* Defensive programming: log the error if a logging facility exists. */
        fprintf(stderr, "insertAtEnd: NULL list pointer\n");
        return -1;
    }

    /* 2. Allocate the new node. */
    Node *newNode = createNode(value);
    if (!newNode) {
        /* Allocation failed – propagate the error. */
        fprintf(stderr, "insertAtEnd: memory allocation failed\n");
        return -1;
    }

    /* 3. If the list is empty, the new node becomes the head. */
    if (isEmpty(list)) {
        list->head = newNode;
        return 0;
    }

    /* 4. Otherwise, traverse to the last node and append. */
    Node *current = list->head;
    while (current->next != NULL) {
        current = current->next;
    }
    current->next = newNode;

    return 0;
}
