#include <errno.h>

/* ------------------------------------------------------------------
 * Helper: Allocate a 2‑D integer matrix of dimensions rows × cols.
 * Returns a pointer to the matrix on success, or NULL on failure.
 * On failure, all memory allocated by this function is freed.
 * ------------------------------------------------------------------ */
static int **allocate_matrix(size_t rows, size_t cols)
{
    /* Allocate the array of row pointers */
    int **matrix = calloc(rows, sizeof(int *));
    if (!matrix) {
        fprintf(stderr, "calloc failed for row pointers: %s\n", strerror(errno));
        return NULL;
    }

    /* Allocate each row */
    for (size_t i = 0; i < rows; ++i) {
