/* Assumptions:
 *   - vocabulary is an array of structs with members:
 *         char english[ENGLISH_MAX];
 *         char alien[ALIEN_MAX];
 *   - MAX_VOCABULARY is the array capacity.
 *   - ENGLISH_MAX and ALIEN_MAX are defined to the desired buffer sizes.
 */
#include <stdio.h>
#include <string.h>
#include <errno.h>

#define ENGLISH_MAX 64
#define ALIEN_MAX   64
#define MAX_VOCABULARY 1024

typedef struct {
    char english[ENGLISH_MAX];
    char alien[ALIEN_MAX];
} Word;

Word vocabulary[MAX_VOCABULARY];
size_t vocabularySize = 0;

int load_vocabulary(const char *filename)
{
    FILE *file = fopen(filename, "r");
    if (!file) {
        perror("Error opening vocabulary file");
        return -1;
    }

    /* Buffer to hold an entire line (including newline). */
    char line[ENGLISH_MAX + ALIEN_MAX + 32];   /* +32 for safety margin */

    while (fgets(line, sizeof(line), file)) {
        /* Skip empty lines or lines that start with a comment marker. */
        if (line[0] == '\n' || line[0] == '#')
            continue;

        /* Ensure we have space in the array. */
        if (vocabularySize >= MAX_VOCABULARY) {
            fprintf(stderr,
                    "Vocabulary limit (%zu) reached – truncating input.\n",
                    MAX_VOCABULARY);
            break;
        }

        /* Use sscanf with width limits to parse two tokens. */
        int matched = sscanf(line,
                             "%63s %63s",
                             vocabulary[vocabularySize].english,
                             vocabulary[vocabularySize].alien);

        if (matched == 2) {
            /* Successful parse – increment counter. */
            vocabularySize++;
        } else {
            /* Handle malformed lines gracefully. */
            fprintf(stderr,
                    "Warning: malformed line %zu: \"%s\"\n",
                    vocabularySize + 1,
                    line);
        }
    }

    if (ferror(file)) {
        perror("Error reading vocabulary file");
        fclose(file);
        return -1;
    }

    fclose(file);
    return 0;
}
```

