    /* Tokenise the string.  We support both "MM/DD/YYYY" and
     * "YYYY/MM/DD" by checking the length of the first token. */
    char *saveptr;
    char *token = strtok_r(date_copy, "/", &saveptr);
    if (token == NULL) {
        free(date_copy);
        return -1;
