    if (!filename || !plaintext || !xor_key) {
        fprintf(stderr, "Error: NULL argument supplied.\n");
        return EXIT_FAILURE;
    }

    if (file_size == 0) {
        fprintf(stderr, "Error: file_size is zero.\n");
        return EXIT_FAILURE;
    }

