```c
/**
 * Allocate and initialise an array of Subnet structures.
 *
 * @param base_address  The starting IP address of the network.
 * @param subnet_mask   The mask that defines the size of each subnet.
 * @param out_subnets   Pointer to the array that will receive the allocation.
 * @param out_count     Pointer to the number of subnets returned.
 *
 * @return 0 on success, non‑zero error code on failure.
 *
 * The caller is responsible for freeing *out_subnets with free().
 */
int allocate_subnets(ip_addr_t base_address,
                     ip_addr_t subnet_mask,
                     Subnet **out_subnets,
                     size_t *out_count)
{
    /* Validate input pointers */
    if (!out_subnets || !out_count) {
        return EINVAL;          /* Invalid argument */
    }

    /* Compute the number of hosts per subnet */
    uint32_t hosts_per_subnet = get_num_hosts(subnet_mask);
    if (hosts_per_subnet == 0) {
        return EINVAL;          /* Invalid subnet mask */
    }

    /* Compute the number of subnets that fit into the network */
    uint32_t subnets_needed = get_num_subnets(subnet_mask);
    if (subnets_needed == 0) {
        return EINVAL;          /* Invalid mask or overflow */
    }

    /* Prevent integer overflow when allocating the array */
    if (subnets_needed > SIZE_MAX / sizeof(Subnet)) {
        return EOVERFLOW;       /* Allocation size too large */
    }

    /* Allocate zero‑initialised memory */
    Subnet *array = calloc(subnets_needed, sizeof(Subnet));
    if (!array) {
        return ENOMEM;          /* Allocation failed */
    }

    /* Initialise each subnet safely */
    for (size_t i = 0; i < subnets_needed; ++i) {
        /* Check for multiplication overflow */
        if (i > UINT32_MAX / hosts_per_subnet) {
            free(array);
            return EOVERFLOW;
        }

        uint32_t offset = (uint32_t)(i * hosts_per_subnet);

        /* Check for addition overflow */
        if (offset > UINT32_MAX - base_address) {
            free(array);
            return EOVERFLOW;
        }

        array[i].subnet_address = base_address + offset;
        array[i].subnet_mask    = subnet_mask;
        array[i].num_hosts      = hosts_per_subnet;
    }

    *out_subnets = array;
    *out_count   = subnets_needed;
    return 0;   /* Success */
}
