/* ------------------------------------------------------------------
 * Secure input helper: reads a line from stdin and converts it to an
 * integer with full bounds checking.  No buffer overflows, no
 * format‑string vulnerabilities, and no undefined behaviour.
 * ------------------------------------------------------------------ */
#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>
#include <string.h>

/* Maximum line length we will accept (including newline and NUL). */
#define MAX_INPUT_LEN 64

/* Reads a line from stdin into `buf`.  Returns 0 on success, -1 on EOF. */
static int read_line(char *buf, size_t bufsize)
{
    if (fgets(buf, (int)bufsize, stdin) == NULL) {
        /* EOF or error */
        return -1;
    }

    /* Strip trailing newline if present */
    size_t len = strlen(buf);
    if (len > 0 && buf[len - 1] == '\n') {
        buf[len - 1] = '\0';
    }
    return 0;
}

/* Safely parses an integer from a string.  Returns 0 on success, -1 on error. */
static int parse_int(const char *str, int *out)
{
    char *endptr;
    long val;

    errno = 0;                     /* reset errno before call */
    val = strtol(str, &endptr, 10); /* base 10 */

    /* Check for conversion errors */
    if (errno != 0 || endptr == str || *endptr != '\0') {
        return -1; /* invalid integer */
    }

    /* Ensure the value fits in an int */
    if (val < INT_MIN || val > INT_MAX) {
        return -1; /* out of range */
    }

    *out = (int)val;
    return 0;
}

/* ------------------------------------------------------------------
 * Updated thermostat case
