### 2.  Secure Code

```c
/*
 *  Secure XOR “cipher” – toy example only.
 *
 *  Parameters
 *      plaintext      – NUL‑terminated input string (must not be NULL)
 *      key            – NUL‑terminated key string (must not be NULL)
 *      keylen         – length of key in bytes (must be > 0)
 *      ciphertext     – pre‑allocated buffer for output (must not be NULL)
 *      ciphertext_len – size of the ciphertext buffer in bytes
 *
 *  Returns
 *      ciphertext on success, or NULL on error.
 *
 *  Notes
 *      • The function does **not** perform any cryptographic
 *        validation; it is only a demonstration of safe pointer
 *        handling and bounds checking.
 *      • In a real deployment, replace this with a proper
 *        authenticated encryption algorithm (e.g., AES‑GCM).
 */

#include <stddef.h>
#include <string.h>
#include <errno.h>

/* Helper macro for error handling */
#define RETURN_NULL_ON_ERROR(cond, err) \
    do { if (cond) { errno = err; return NULL; } } while (0)

char *
secure_xor_cipher(const char *plaintext,
                  const char *key,
                  size_t keylen,
                  char *ciphertext,
                  size_t ciphertext_len)
{
    /* 1. Validate inputs */
    RETURN_NULL_ON_ERROR(plaintext == NULL, EINVAL);
    RETURN_NULL_ON_ERROR(key == NULL, EINVAL);
    RETURN_NULL_ON_ERROR(ciphertext == NULL, EINVAL);
    RETURN_NULL_ON_ERROR(keylen == 0, EINVAL);

    /* 2. Compute plaintext length once */
    size_t pt_len = strlen(plaintext);          /* NUL‑terminated */
    size_t needed  = pt_len + 1;                /* +1 for terminating NUL */

    /* 3. Check buffer size */
    RETURN_NULL_ON_ERROR(ciphertext_len < needed, ERANGE);

    /* 4. Perform XOR */
    for (size_t i = 0; i < pt_len; ++i) {
        ciphertext[i] = plaintext[i] ^ key[i % keylen];
    }

    /* 5. NUL‑terminate */
    ciphertext[pt_len] = '\0';

    return ciphertext;
}
```

