    if (text == NULL) { /* defensive check – should never happen */
        fprintf(stderr, "Error: input text is NULL.\n");
        return EXIT_FAILURE;
    }

    /*  3. Use size_t for lengths – unsigned, platform‑independent  */
    size_t text_len = strlen(text);

    /*  4. Process each character safely  */
    for (size_t i = 0; i < text_len; ++i) {
        /*  a. Cast to unsigned char before calling toupper()  */
        unsigned char uc = (unsigned char)text[i];
        char letter = (char)toupper(uc);

        /*  b. Lookup Morse code – handle unknown characters gracefully  */
        const char *morse = lookup_morse(letter);
        if (morse == NULL) {
            fprintf(stderr, "Warning: character '%c' (0x%02x) has no Morse mapping.\n",
                    text[i], uc);
            continue; /* skip or replace with a placeholder if desired */
        }

        /*  c. Output the Morse code – keep output logic separate  */
        printf("%s ", morse);
    }
    printf("\n");

    return EXIT_SUCCESS;
}
