#include <stdlib.h>
#include <string.h>
#include <errno.h>

/**
 * Decrypts a ciphertext using a simple XOR cipher.
 *
 * @param ciphertext The input string to decrypt. Must be a valid NUL‑terminated
 *                   string.  The function does **not** modify this buffer.
 * @param key        The key used for XOR. Must be a valid NUL‑terminated
 *                   string and must not be empty.
 *
 * @return A newly allocated NUL‑terminated string containing the plaintext,
 *         or NULL on error.  The caller is responsible for freeing the
 *         returned buffer with `free()`.  On error, errno is set to indicate
 *         the failure reason:
 *           - EINVAL:  ciphertext or key is NULL, or key is empty.
 *           - ENOMEM:  memory allocation failed.
