    if (ciphertext == NULL || key == NULL) {
        errno = EINVAL;
        return NULL;
    }

    /* 2. Compute lengths once */
    const size_t ct_len = strlen(ciphertext);
    const size_t key_len = strlen(key);

    /* 3. Reject empty key to avoid modulo‑by‑zero */
    if (key_len == 0) {
        errno = EINVAL;
        return NULL;
    }

    /* 4. Allocate output buffer (+1 for NUL terminator) */
    char *plaintext = malloc(ct_len + 1);
    if (plaintext == NULL) {
        errno = ENOMEM;
        return NULL;
    }

    /* 5. Perform XOR decryption */
    for (size_t i = 0; i < ct_len; ++i) {
        plaintext[i] = ciphertext[i] ^ key[i % key_len];
    }

    /* 6. NUL‑terminate the result */
    plaintext[ct_len] = '\0';

    return plaintext;
}
