    if (str == endptr || *endptr != '\0') {
        return -1;
    }
    /* Check for overflow/underflow */
    if ((errno == ERANGE && (val == LONG_MAX || val == LONG_MIN)) ||
        val < INT_MIN || val > INT_MAX) {
        return -1;
    }
    *out = (int)val;
    return 0;
}

