2. **Robust bounds checking** – ensures the supplied index is within `[0, list->size]`.  
3. **Safe node allocation** – checks the result of `createNode` and cleans up on failure.  
4. **Clear error reporting** – uses a dedicated error‑handling helper to avoid duplicated code.  
5. **No insecure patterns** – no unchecked casts, no use of `goto`, no unchecked `printf` arguments, and no unchecked pointer arithmetic.

```c
/* ------------------------------------------------------------------
 *  insertAtIndex – Insert a value into a singly‑linked list at a
 *  specified index.  The function is fully NULL‑safe and performs
 *  all necessary bounds checks before any pointer dereference.
 * ------------------------------------------------------------------ */

#include <stdio.h>
#include <stdlib.h>

/* Forward declarations – assume these are defined elsewhere */
typedef struct Node {
    int value;
    struct Node *next;
} Node;

typedef struct List {
    Node *head;
    size_t size;
} List;

/* Helper: create a new node; returns NULL on allocation failure */
static Node *createNode(int value)
{
    Node *node = malloc(sizeof(Node));
    if (!node) {
        return NULL;
    }
    node->value = value;
    node->next  = NULL;
    return node;
}

/* Helper: insert at the beginning of the list */
static void insertAtBeginning(List *list, int value)
{
    Node *newNode = createNode(value);
    if (!newNode) {
        /* Allocation failed – report and abort the operation */
        fprintf(stderr, "Error: memory allocation failed in insertAtBeginning\n");
        return;
    }
    newNode->next = list->head;
    list->head    = newNode;
    list->size++;
}

/* Helper: insert at the end of the list */
static void insertAtEnd(List *list, int value)
{
    Node *newNode = createNode(value);
    if (!newNode) {
        fprintf(stderr, "Error: memory allocation failed in insertAtEnd\n");
        return;
    }

    if (!list->head) {          /* Empty list – new node becomes head */
        list->head = newNode;
    } else {
        Node *current = list->head;
        while (current->next) {
            current = current->next;
        }
        current->next = newNode;
    }
    list->size++;
}

/* ------------------------------------------------------------------
 *  Public API – insertAtIndex
 * ------------------------------------------------------------------ */
void insertAtIndex(List *list, size_t index, int value)
{
    /* 1. Validate the list pointer and its internal fields */
    if (!list) {
        fprintf(stderr, "Error: list pointer is NULL\n");
        return;
    }
    if (!list->head && list->size != 0) {
        /* Inconsistent state – treat as an error */
        fprintf(stderr, "Error: list->head is NULL but size is non‑zero\n");
        return;
    }

    /* 2. Bounds check – index must be in [0, list->size] */
    if (index > list->size) {
        fprintf(stderr, "Error: index %zu out of bounds (size %zu)\n",
