| Potential memory leak on failure | Return early without leaking | Ensures that a failed allocation does not leave dangling pointers. |

```c
/* ------------------------------------------------------------------
 *  Linked‑List helpers – safe, defensive implementation
 * ------------------------------------------------------------------ */

/* Forward declarations – assume these are defined elsewhere */
typedef struct Node {
    int value;
    struct Node *next;
} Node;

typedef struct LinkedList {
    Node *head;
    size_t size;
} LinkedList;

/* Create a new node – returns NULL on allocation failure */
static Node *createNode(int value)
{
    Node *node = malloc(sizeof(Node));
    if (node == NULL) {
        /* Allocation failed – caller must handle */
        return NULL;
    }
    node->value = value;
    node->next  = NULL;
    return node;
}

/* Return true if the list is empty or the list pointer itself is NULL */
static bool isEmpty(const LinkedList *list)
{
    return (list == NULL) || (list->head == NULL);
}

/* Insert a new node at the beginning of the list */
void insertAtBeginning(LinkedList *list, int value)
{
    /* Defensive checks – avoid NULL dereference */
    if (list == NULL) {
        /* In a real system you might log this error */
        return;
    }

    Node *newNode = createNode(value);
    if (newNode == NULL) {
        /* Allocation failed – nothing to insert */
        return;
    }

    /* If the list is empty, simply point head to the new node */
    if (isEmpty(list)) {
        list->head = newNode;
    } else {
        /* Safe: list->head is guaranteed non‑NULL here */
        newNode->next = list->head;
        list->head    = newNode;
    }

    /* Increment size only after a successful insertion */
    list->size++;
}

/* Insert a new node at the end of the list */
void insertAtEnd(LinkedList *list, int value)
{
    /* Defensive checks – avoid NULL dereference */
    if (list == NULL) {
        return;
    }

    Node *newNode = createNode(value);
    if (newNode == NULL) {
        return;
    }

    /* If the list is empty, reuse the beginning‑insertion logic */
    if (isEmpty(list)) {
        list->head = newNode;
    } else {
        /* Walk to the last node – safe because list->head is non‑NULL */
        Node *current = list->head;
        while (current->next != NULL) {
            current = current->next;
        }
        current->next = newNode;
    }

    list->size++;
}
```

