#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Example allocation helper that returns a pointer to a sub‑block
   inside a larger pool.  The caller must keep the original pool
   pointer for freeing. */
void *allocate_subblock(void *pool, size_t offset, size_t size)
{
    /* Simple bounds check – in production code you would want
       a more robust allocator. */
    if (offset + size > 500) {
        return NULL;
    }
    return (char *)pool + offset;
}

int main(void)
{
    /* Allocate a single contiguous block of 500 bytes. */
    void *memoryPool = malloc(500);
    if (!memoryPool) {
        perror("malloc");
        return EXIT_FAILURE;
    }

    /* Example: create two sub‑blocks inside the pool. */
    void *ptr2 = allocate_subblock(memoryPool, 100, 50);   /* offset 100 */
    void *ptr3 = allocate_subblock(memoryPool, 200, 75);   /* offset 200 */

    if (!ptr2 || !ptr3) {
        fprintf(stderr, "Failed to allocate sub‑blocks\n");
        free(memoryPool);          /* clean up the original pool */
        return EXIT_FAILURE;
    }

    printf("Allocated block of size 500 at address %p.\n", memoryPool);
    printf("Sub‑block 1 at %p (offset 100)\n", ptr2);
    printf("Sub‑block 2 at %p (offset 200)\n", ptr3);

    /* Use ptr2 and ptr3 as needed ... */

    /* No need to free ptr2 or ptr3 – they are just pointers into
       memoryPool.  Only free the original pool once. */
    free(memoryPool);

    return EXIT_SUCCESS;
}
```

### Why this is secure

