    uint32_t subnet_mask;    /* IPv4 mask in network byte order */
    uint32_t num_hosts;      /* Number of usable hosts in the subnet */
} subnet_t;

/*
 * Allocate and initialise an array of `num_subnets` subnet_t structures.
 *
 * Parameters:
 *   subnet_address - base address for the first subnet (network byte order)
 *   subnet_mask    - subnet mask (network byte order)
 *   num_hosts      - number of hosts per subnet
 *   num_subnets    - number of subnets to create
 *
 * Returns:
 *   Pointer to a heap‑allocated array of subnet_t on success.
 *   NULL on failure (e.g., invalid arguments or memory allocation error).
 *
 * The caller is responsible for freeing the returned array with free().
 */
subnet_t *create_subnets(uint32_t subnet_address,
                         uint32_t subnet_mask,
                         uint32_t num_hosts,
                         size_t num_subnets)
{
    /* 1. Basic sanity checks */
    if (num_subnets == 0) {
        errno = EINVAL;
        return NULL;
    }

    /* 2. Allocate memory safely */
    subnet_t *subnets = calloc(num_subnets, sizeof(subnet_t));
    if (!subnets) {
        /* calloc already sets errno on failure */
        return NULL;
    }

    /* 3. Initialise each subnet */
    for (size_t i = 0; i < num_subnets; ++i) {
        /* Prevent integer overflow when computing the address offset */
        uint64_t offset = (uint64_t)i * (uint64_t)num_hosts;
        if (offset > UINT32_MAX) {
