 *  Extract the year component from a date string of the form
 *      YYYY/MM/DD
 *  Returns:
 *      >= 0  – the parsed year
 *      -1    – parsing error (NULL input, malformed string, or out‑of‑range year)
 * ------------------------------------------------------------------ */
static int safe_extract_year(const char *date_string)
{
    if (date_string == NULL) {
        return -1;          /* NULL input */
    }

    /* Make a writable copy because strtok_r modifies the string */
    char *copy = strdup(date_string);
    if (copy == NULL) {
        return -1;          /* allocation failure */
    }

    char *token;
    char *saveptr;
    int year = -1;

    /* 1st token: year */
    token = strtok_r(copy, "/", &saveptr);
    if (token == NULL) {
        free(copy);
        return -1;          /* missing year */
    }

    /* Convert year safely */
    char *endptr;
    errno = 0;
    long val = strtol(token, &endptr, 10);
    if (errno != 0 || *endptr != '\0' || val < 0 || val > 9999) {
        free(copy);
        return -1;          /* invalid year format or out of range */
    }
    year = (int)val;

    /* 2nd token: month (optional, but we consume it to keep the parser in sync) */
    token = strtok_r(NULL, "/", &saveptr);
    if (token == NULL) {
        free(copy);
        return -1;          /* missing month */
    }

    /* 3rd token: day (optional) */
    token = strtok_r(NULL, "/", &saveptr);
    /* day may be missing – that's fine for this function */

    free(copy);
    return year;
