2. Explicitly checks that the computed difference is within the valid range of a chess‑board‑style grid (0–7 for an 8×8 board, but the check is generic).
3. Keeps the original logic but guards against division by zero and odd‑difference mid‑row calculations.

```c
#include <stdint.h>   // for int64_t
#include <stdbool.h>  // for bool
#include <stdlib.h>   // for abs

/* Helper: safe signed subtraction that returns a bool indicating success */
static bool safe_sub_int(int a, int b, int64_t *result)
{
    /* In C, signed overflow is UB.  We use int64_t to hold the result safely. */
    *result = (int64_t)a - (int64_t)b;
    /* If the result cannot be represented in a 32‑bit int, we treat it as invalid. */
    if (*result < INT32_MIN || *result > INT32_MAX) {
        return false;
    }
    return true;
}

/* Secure move‑validation routine */
bool is_valid_move(const Game *game, int startRow, int startCol,
                   int endRow, int endCol, int player)
{
    /* 1. Compute row difference safely */
    int64_t rowDiff;
    if (!safe_sub_int(endRow, startRow, &rowDiff)) {
        /* Overflow detected – reject the move */
        return false;
    }

    /* 2. Direction is +1 for RED, -1 for other players */
    const int direction = (player == RED) ? 1 : -1;

    /* 3. Ensure the difference is within the board bounds (generic check) */
    if (rowDiff < -7 || rowDiff > 7) {   /* 7 is the max distance on an 8×8 board */
        return false;
    }

    /* 4. One‑step move */
    if (rowDiff == direction) {
        return (abs(endCol - startCol) == 1);
    }

    /* 5. Two‑step capture move */
    if (rowDiff == 2 * direction) {
        /* Mid‑row and mid‑col must be computed safely */
        int midRow = startRow + direction;
        int midCol = startCol + (endCol - startCol) / 2;

        /* Validate mid‑cell is occupied by an opponent */
        if (game->board[midRow][midCol] != EMPTY &&
            game->board[midRow][midCol] != player) {
            return true;   /* valid capture */
        }
    }

    /* All other moves are invalid */
    return false;
}
