The vulnerability is that `scanf("%d", &numFaces)` can read an integer that is larger than the range of `int` or can leave the input buffer in an inconsistent state if the user enters non‑numeric data. A safer approach is to read a line of text with `fgets`, then parse it with `strtol`, which gives you full control over bounds checking and error handling.

```c
#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>

#define MAX_FACES 100   /* example maximum; adjust as needed */
#define INPUT_BUF_SIZE 64

/* Helper: read a line of input safely */
static int read_line(char *buf, size_t size)
{
    if (fgets(buf, (int)size, stdin) == NULL) {
        /* EOF or error – treat as invalid input */
        return 0;
    }
    /* Remove trailing newline if present */
    size_t len = strlen(buf);
    if (len > 0 && buf[len - 1] == '\n') {
        buf[len - 1] = '\0';
    }
    return 1;
}

/* Helper: convert string to integer with range checking */
static int parse_int(const char *str, int *out)
{
    char *endptr;
    long val;

    errno = 0;
    val = strtol(str, &endptr, 10);

    /* Check for conversion errors */
    if (errno != 0 || endptr == str || *endptr != '\0') {
        return 0;          /* invalid integer format */
    }

    /* Ensure the value fits in an int and is within bounds */
    if (val < INT_MIN || val > INT_MAX) {
        return 0;
    }

    *out = (int)val;
    return 1;
}

int main(void)
{
    int numFaces;
    char input[INPUT_BUF_SIZE];

    while (1) {
        printf("Enter number of faces per die (2 to %d): ", MAX_FACES);

        if (!read_line(input, sizeof(input))) {
            printf("\nError reading input. Exiting.\n");
            return EXIT_FAILURE;
        }

        if (!parse_int(input, &numFaces) ||
            numFaces < 2 || numFaces > MAX_FACES) {
            printf("Invalid number of faces! Please choose between 2 and %d.\n",
                   MAX_FACES);
            continue;
        }

        /* Valid input – proceed with the rest of the program */
        break;
    }

    /* ... rest of the program ... */
    return EXIT_SUCCESS;
}
```

### Why this is secure

| Issue | Fix |
|-------|-----|
| **Unbounded input** – `scanf` can leave the input buffer in an inconsistent state if the user types non‑numeric data. | `fgets` reads a fixed‑size line, guaranteeing no overflow of the buffer. |
| **No range checking** – `scanf` accepts any integer, even values outside the intended range. | `strtol` parses the string and we explicitly check that the value is between 2 and `MAX_FACES`. |
| **Potential integer overflow** – `strtol` returns a `long`; we verify that the result fits in an `int`. | Explicit bounds check against `INT_MIN`/`INT_MAX`. |
| **Error handling** – `scanf` silently fails on bad input. | `parse_int` returns a boolean indicating success; we loop until valid input is received. |

This pattern is widely recommended for secure C input handling and eliminates the buffer‑overflow risk while providing clear, user‑friendly validation.

