{
    if (fgets(buf, (int)size, stdin) == NULL) {
        return -1;          /* EOF or error */
    }
    /* Remove trailing newline if present */
    size_t len = strlen(buf);
    if (len > 0 && buf[len - 1] == '\n') {
        buf[len - 1] = '\0';
    }
    return 0;
}

/* Helper: parse three integers from a string safely */
static int parse_three_ints(const char *line, int *n, int *m, int *k)
{
    /* Use sscanf with a return value check */
    int matched = sscanf(line, "%d %d %d", n, m, k);
    return (matched == 3) ? 0 : -1;
}

/* Helper: validate that a value is within a safe range */
static int validate_positive(int value, const char *name)
{
    if (value <= 0) {
        fprintf(stderr, "Error: %s must be positive.\n", name);
        return -1;
    }
    if (value > MAX_GRAPH_SIZE) {
        fprintf(stderr, "Error: %s (%d) exceeds maximum allowed (%d).\n",
                name, value, MAX_GRAPH_SIZE);
        return -1;
    }
    return 0;
}

