/*  string_wrapper.c  */
#include "string_wrapper.h"
#include <stdlib.h>
#include <string.h>
#include <errno.h>

/* Internal representation – kept private to the module. */
struct String {
    char *data;      /* NUL‑terminated string */
    size_t length;   /* number of characters (excluding NUL) */
};

/* Helper: duplicate a string safely.
 * Returns NULL on failure and sets errno appropriately. */
static char *safe_strdup(const char *src)
{
    if (src == NULL) {
        errno = EINVAL;
        return NULL;
    }

    /* Use malloc + memcpy to avoid the undefined behaviour of strdup
     * on some platforms that may return a pointer to a read‑only
     * string. */
    size_t len = strlen(src);
    char *dup = malloc(len + 1);
    if (dup == NULL) {
        /* errno already set by malloc */
        return NULL;
    }
    memcpy(dup, src, len + 1);   /* includes terminating NUL */
    return dup;
}

String *new_string(const char *src)
{
    if (src == NULL) {
        errno = EINVAL;
        return NULL;
    }

    /* Allocate the wrapper structure. */
    String *s = malloc(sizeof(String));
    if (s == NULL) {
        /* errno set by malloc */
        return NULL;
    }

    /* Duplicate the source string. */
    s->data = safe_strdup(src);
    if (s->data == NULL) {
        /* Allocation failed – clean up wrapper. */
        free(s);
        return NULL;
    }

    s->length = strlen(src);   /* safe – src is non‑NULL */
    return s;
}

void free_string(String *s)
{
    if (s == NULL) {
        /* Graceful no‑op – callers may pass NULL. */
        return;
    }

    /* Free the duplicated string first. */
    free(s->data);
    s->data = NULL;   /* defensive: avoid dangling pointer */

    /* Finally free the wrapper itself. */
    free(s);
}
```

