/*  graph.c  –  Secure graph allocation and cleanup  */
#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <string.h>

/* ------------------------------------------------------------------ */
/*  Data structures                                                   */
/* ------------------------------------------------------------------ */
struct node {
    int vertex;
    struct node *next;
};

struct Graph {
    size_t vertices;      /* number of vertices (use size_t for sizes) */
    struct node **adjList;/* array of adjacency‑list heads */
};

/* ------------------------------------------------------------------ */
/*  Helper: safe allocation of a Graph                                */
/* ------------------------------------------------------------------ */
static struct Graph *create_graph(size_t vertices)
{
    /* Allocate the Graph structure itself */
    struct Graph *g = calloc(1, sizeof(*g));
    if (!g) {
        fprintf(stderr, "Error: calloc for Graph failed: %s\n", strerror(errno));
        return NULL;
    }

    g->vertices = vertices;

    /* Allocate the adjacency‑list array and initialise all entries to NULL */
    g->adjList = calloc(vertices, sizeof(*g->adjList));
    if (!g->adjList) {
        fprintf(stderr, "Error: calloc for adjacency list failed: %s\n", strerror(errno));
        free(g);          /* clean up the Graph structure */
        return NULL;
    }

    /* All pointers are already NULL because of calloc – no extra init needed */
    return g;
}

/* ------------------------------------------------------------------ */
/*  Helper: free a graph (including all adjacency lists)             */
/* ------------------------------------------------------------------ */
static void free_graph(struct Graph *g)
{
    if (!g) return;

    /* Free each adjacency list chain */
    for (size_t i = 0; i < g->vertices; ++i) {
        struct node *curr = g->adjList[i];
        while (curr) {
            struct node *next = curr->next;
            free(curr);
            curr = next;
        }
    }

    /* Free the adjacency list array and the Graph itself */
    free(g->adjList);
    free(g);
}

/* ------------------------------------------------------------------ */
/*  Example usage (main)                                              */
/* ------------------------------------------------------------------ */
int main(void)
{
    /* Example: create a graph with 5 vertices */
    const size_t V = 5;
    struct Graph *graph = create_graph(V);
    if (!graph) {
        /* Allocation failed – exit gracefully */
        return EXIT_FAILURE;
    }

    /* ... (graph operations would go here) ... */

    /* Clean up before exiting */
    free_graph(graph);
    return EXIT_SUCCESS;
}
```

